import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { supabase } from './supabaseClient';
import RichTextEditor from './components/RichTextEditor';
import UserRoleBadge from './components/UserRoleBadge';
import TrendingTicker from './components/TrendingTicker';
import StatisticsPage from './components/StatisticsPage';
import './App.css';

// ==================== LOGIN COMPONENT ====================
function Login({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const { data, error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) setError(error.message);
    else onLogin(data.user);
    setLoading(false);
  };

  return (
    <div className="split-screen">
      <div className="split-left">
        <div className="hero-overlay">
          <img src="/images/logo-presidence-rdc.png" alt="Présidence RDC" className="hero-logo" />
          <h1>Réforme Constitutionnelle</h1>
          <h2>Consultation Nationale</h2>
          <p className="hero-quote">"La voix de 80 millions de Congolais"</p>
        </div>
      </div>
      <div className="split-right">
        <div className="auth-card">
          <h2>Connexion</h2>
          <p className="subtitle">Espace citoyen sécurisé</p>
          {error && <div className="error">{error}</div>}
          <form onSubmit={handleSubmit}>
            <input type="email" placeholder="Email" value={email} onChange={(e) => setEmail(e.target.value)} required />
            <input type="password" placeholder="Mot de passe" value={password} onChange={(e) => setPassword(e.target.value)} required />
            <button type="submit" disabled={loading} className="btn-gold">{loading ? 'Chargement...' : 'Se connecter'}</button>
          </form>
          <p className="footer-link">Pas encore de compte ? <Link to="/signup">Créer un compte</Link></p>
        </div>
      </div>
    </div>
  );
}

// ==================== SIGNUP COMPONENT ====================
function Signup({ onSignup }) {
  const [form, setForm] = useState({ email: '', password: '', fullName: '', province: '', role: 'citizen' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const provinces = ['Kinshasa', 'Kongo Central', 'Haut-Katanga', 'Nord-Kivu', 'Sud-Kivu', 'Équateur', 'Kasaï', 'Lualaba'];

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    const { data, error } = await supabase.auth.signUp({
      email: form.email,
      password: form.password,
      options: { data: { full_name: form.fullName, province: form.province, role: form.role } }
    });
    if (error) setError(error.message);
    else if (data.user) {
      await supabase.from('profiles').insert([{ id: data.user.id, email: form.email, full_name: form.fullName, province: form.province, role: form.role }]);
      onSignup(data.user);
    }
    setLoading(false);
  };

  return (
    <div className="split-screen">
      <div className="split-left">
        <div className="hero-overlay">
          <img src="/images/logo-presidence-rdc.png" alt="Présidence RDC" className="hero-logo" />
          <h1>Devenir acteur du changement</h1>
          <h2>Inscrivez-vous</h2>
        </div>
      </div>
      <div className="split-right">
        <div className="auth-card">
          <h2>Créer mon compte</h2>
          {error && <div className="error">{error}</div>}
          <form onSubmit={handleSubmit}>
            <input type="text" placeholder="Nom complet" value={form.fullName} onChange={(e) => setForm({...form, fullName: e.target.value})} required />
            <input type="email" placeholder="Email" value={form.email} onChange={(e) => setForm({...form, email: e.target.value})} required />
            <input type="password" placeholder="Mot de passe (min. 6 caractères)" value={form.password} onChange={(e) => setForm({...form, password: e.target.value})} required />
            <select value={form.province} onChange={(e) => setForm({...form, province: e.target.value})} required>
              <option value="">Sélectionnez votre province</option>
              {provinces.map(p => <option key={p} value={p}>{p}</option>)}
            </select>
            <select value={form.role} onChange={(e) => setForm({...form, role: e.target.value})}>
              <option value="citizen">Citoyen</option>
              <option value="political_party">Parti politique</option>
              <option value="civil_society">Société civile</option>
            </select>
            <button type="submit" disabled={loading} className="btn-gold">{loading ? 'Inscription...' : 'Créer mon compte'}</button>
          </form>
          <p className="footer-link">Déjà inscrit ? <Link to="/login">Se connecter</Link></p>
        </div>
      </div>
    </div>
  );
}

// ==================== HOMEPAGE ====================
function Homepage({ user }) {
  const images = [
    { src: '/images/gallery/forest-bassin-congo-fr.jpg', title: 'Bassin du Congo', desc: 'Patrimoine mondial' },
    { src: '/images/gallery/okapi-espece-protegee-fr.jpg', title: 'Okapi', desc: 'Espèce protégée' },
    { src: '/images/gallery/gorille-montagne-virunga-fr.jpg', title: 'Gorille des montagnes', desc: 'Virunga' },
    { src: '/images/gallery/volcan-nyiragongo-goma-fr.jpg', title: 'Nyiragongo', desc: 'Merveille naturelle' },
    { src: '/images/gallery/fleuve-congo-kinshasa-fr.jpg', title: 'Fleuve Congo', desc: 'Artère vitale' },
    { src: '/images/gallery/president-tshisekedi-rdc-fr.jpg', title: 'Félix Tshisekedi', desc: 'Président de la République' },
  ];

  return (
    <div className="homepage">
      <TrendingTicker />
      <section className="hero-main">
        <div className="hero-content">
          <div className="hero-badge">RÉPUBLIQUE DÉMOCRATIQUE DU CONGO</div>
          <h1>Plateforme de<br />Réforme Constitutionnelle</h1>
          <p>Participez à la construction d'un avenir meilleur pour notre nation</p>
          {user ? (
            <Link to="/dashboard" className="btn-gold btn-large">Soumettre une proposition</Link>
          ) : (
            <Link to="/signup" className="btn-gold btn-large">Participer maintenant</Link>
          )}
        </div>
      </section>
      <section className="gallery-section">
        <div className="container">
          <div className="section-title">
            <span className="accent">NOTRE PATRIMOINE</span>
            <h2>La richesse de la RDC</h2>
          </div>
          <div className="gallery-grid">
            {images.map((img, i) => (
              <div key={i} className="gallery-card">
                <img src={img.src} alt={img.title} />
                <div className="card-info">
                  <h3>{img.title}</h3>
                  <p>{img.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>
    </div>
  );
}

// ==================== DASHBOARD ====================
function Dashboard({ user }) {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const [category, setCategory] = useState('');
  const [files, setFiles] = useState([]);
  const [proposals, setProposals] = useState([]);
  const [message, setMessage] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [profile, setProfile] = useState(null);

  useEffect(() => {
    const fetchProfile = async () => {
      const { data } = await supabase.from('profiles').select('*').eq('id', user.id).single();
      if (data) setProfile(data);
    };
    const fetchProposals = async () => {
      const { data } = await supabase.from('proposals').select('*').order('created_at', { ascending: false });
      if (data) setProposals(data);
    };
    fetchProfile();
    fetchProposals();
  }, [user]);

  const uploadImages = async () => {
    const urls = [];
    for (const file of files) {
      const fileName = `${Date.now()}-${file.name}`;
      const { error } = await supabase.storage.from('proposal-images').upload(fileName, file);
      if (!error) {
        const { data: { publicUrl } } = supabase.storage.from('proposal-images').getPublicUrl(fileName);
        urls.push(publicUrl);
      }
    }
    return urls;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    setMessage('');
    const imageUrls = await uploadImages();
    const { error } = await supabase.from('proposals').insert([{
      user_id: user.id,
      title,
      content,
      category,
      image_urls: imageUrls,
      status: 'pending'
    }]);
    if (error) setMessage('Erreur: ' + error.message);
    else {
      setMessage('Proposition soumise avec succès !');
      setTitle('');
      setContent('');
      setCategory('');
      setFiles([]);
      window.location.reload();
    }
    setSubmitting(false);
  };

  return (
    <div className="dashboard-page">
      <div className="dashboard-grid">
        <div className="form-card">
          <div className="card-header">
            <h2>Soumettre une proposition</h2>
            <p>Partagez votre vision pour la réforme constitutionnelle</p>
          </div>
          {message && <div className="success">{message}</div>}
          <form onSubmit={handleSubmit}>
            <input type="text" placeholder="Titre de la proposition" value={title} onChange={(e) => setTitle(e.target.value)} required />
            <select value={category} onChange={(e) => setCategory(e.target.value)} required>
              <option value="">Sélectionnez une catégorie</option>
              <option value="Gouvernance">Gouvernance</option>
              <option value="Justice">Justice</option>
              <option value="Élections">Élections</option>
              <option value="Décentralisation">Décentralisation</option>
            </select>
            <RichTextEditor value={content} onChange={setContent} />
            <input type="file" multiple accept="image/*" onChange={(e) => setFiles(Array.from(e.target.files))} />
            <button type="submit" disabled={submitting} className="btn-gold btn-full">{submitting ? 'Soumission...' : 'Soumettre'}</button>
          </form>
        </div>
        <div className="feed-card">
          <div className="card-header">
            <h3>Propositions récentes</h3>
          </div>
          <div className="feed-list">
            {proposals.map(p => (
              <div key={p.id} className="feed-item">
                <div className="feed-header">
                  <div className="user-avatar">👤</div>
                  <div>
                    <div className="user-name">{profile?.full_name || 'Citoyen'}</div>
                    {profile && <UserRoleBadge role={profile.role} />}
                  </div>
                  <div className="category-tag">{p.category}</div>
                </div>
                <h4>{p.title}</h4>
                <p className="feed-excerpt">{p.content.substring(0, 150)}...</p>
                {p.image_urls && p.image_urls[0] && <img src={p.image_urls[0]} alt="proposal" className="feed-img" />}
                <div className="feed-footer">
                  <button className="support-btn">🤝 Soutenir</button>
                  <span className="support-count">0 signatures</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

// ==================== MAIN APP ====================
function App() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user || null);
      setLoading(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user || null);
    });
    return () => subscription.unsubscribe();
  }, []);

  if (loading) return <div className="loading-screen"><div className="loader"></div><p>Chargement du portail</p></div>;

  return (
    <BrowserRouter>
      <nav className="navbar">
        <div className="nav-container">
          <Link to="/" className="nav-brand">
            <img src="/images/logo-presidence-rdc.png" alt="Présidence RDC" className="nav-logo" />
            <span className="brand-text">RDC | Réforme Constitutionnelle</span>
          </Link>
          <div className="nav-links">
            <Link to="/">Accueil</Link>
            <Link to="/statistics">Analyses</Link>
            {user && <Link to="/dashboard">Soumettre</Link>}
            {user ? (
              <button onClick={() => supabase.auth.signOut()} className="btn-outline">Déconnexion</button>
            ) : (
              <Link to="/login" className="btn-nav">Connexion</Link>
            )}
          </div>
        </div>
      </nav>
      <Routes>
        <Route path="/" element={<Homepage user={user} />} />
        <Route path="/statistics" element={<StatisticsPage />} />
        <Route path="/login" element={user ? <Navigate to="/dashboard" /> : <Login onLogin={setUser} />} />
        <Route path="/signup" element={user ? <Navigate to="/dashboard" /> : <Signup onSignup={setUser} />} />
        <Route path="/dashboard" element={user ? <Dashboard user={user} /> : <Navigate to="/login" />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
